"""
invoice_service.py
PDF generation logic: take a row dict → produce a PDF file.
Pure functions — no Flask dependencies.
"""
import base64
import copy
import os
import re
from datetime import datetime
from io import BytesIO

from reportlab.lib.colors import HexColor, black, white
from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_RIGHT
from reportlab.lib.pagesizes import letter
from reportlab.lib.units import inch
from reportlab.lib.styles import ParagraphStyle
from reportlab.platypus import Image, Paragraph, SimpleDocTemplate, Spacer, Table, TableStyle
from reportlab.pdfbase import pdfmetrics
from reportlab.pdfbase.ttfonts import TTFont

from config import HOURLY_RATE

# ---------------------------------------------------------------------------
# Embedded logo (Icahn School of Medicine at Mount Sinai) as base64 PNG
# ---------------------------------------------------------------------------
LOGO_B64 = """"""

def _register_calibri():
    """Register Calibri font family. Searches common locations."""
    search_paths = [
        # macOS - Microsoft Office bundled fonts
        "/Applications/Microsoft Excel.app/Contents/Resources/DFonts",
        "/Applications/Microsoft Word.app/Contents/Resources/DFonts",
        "/Applications/Microsoft PowerPoint.app/Contents/Resources/DFonts",
        "/Applications/Microsoft OneNote.app/Contents/Resources/DFonts",
        "/Applications/Microsoft Outlook.app/Contents/Resources/DFonts",
        # macOS - system / user font dirs
        "/Library/Fonts",
        os.path.expanduser("~/Library/Fonts"),
        # Windows
        "C:/Windows/Fonts",
        # Linux
        "/usr/share/fonts/truetype/msttcorefonts",
        "/usr/share/fonts/truetype/calibri",
    ]

    variants = {
        "Calibri":           ["Calibri.ttf", "calibri.ttf"],
        "Calibri-Bold":      ["Calibrib.ttf", "calibrib.ttf", "Calibri Bold.ttf"],
        "Calibri-Italic":    ["Calibrii.ttf", "calibrii.ttf", "Calibri Italic.ttf"],
        "Calibri-BoldItalic": ["Calibriz.ttf", "calibriz.ttf", "Calibri Bold Italic.ttf"],
    }

    registered = {}
    for name, filenames in variants.items():
        for search_dir in search_paths:
            if name in registered:
                break
            for fn in filenames:
                path = os.path.join(search_dir, fn)
                if os.path.isfile(path):
                    try:
                        pdfmetrics.registerFont(TTFont(name, path))
                        registered[name] = path
                        break
                    except Exception:
                        pass

    if "Calibri" in registered:
        from reportlab.pdfbase.pdfmetrics import registerFontFamily
        registerFontFamily(
            "Calibri",
            normal="Calibri",
            bold="Calibri-Bold",
            italic="Calibri-Italic",
            boldItalic="Calibri-BoldItalic",
        )
    return "Calibri" in registered


def _get_fonts():
    """Return (regular, bold, italic, bold-italic) font names."""
    if _register_calibri():
        return "Calibri", "Calibri-Bold", "Calibri-Italic", "Calibri-BoldItalic"
    print("  WARNING: Calibri not found, falling back to Helvetica")
    return "Helvetica", "Helvetica-Bold", "Helvetica-Oblique", "Helvetica-BoldOblique"


FONT, FONT_BOLD, FONT_ITALIC, FONT_BOLD_ITALIC = _get_fonts()


def _logo_image(width=1.23 * inch, height=1.72 * inch):
    """Decode the embedded logo and return a ReportLab Image."""
    data = base64.b64decode(LOGO_B64)
    img = Image(BytesIO(data), width=width, height=height)
    img.hAlign = "LEFT"
    return img


def _extract_ticket_number(issue_key):
    """Extract numeric portion from issue_key like MSD-3312 -> 3312."""
    m = re.search(r"(\d+)$", issue_key)
    return m.group(1) if m else issue_key


def _parse_created_date(date_str):
    """Parse the created date string into a datetime object."""
    for fmt in ("%Y-%m-%d", "%m/%d/%Y", "%m/%d/%y", "%Y/%m/%d",
                "%d-%b-%Y", "%d-%b-%y", "%b %d, %Y",
                "%Y-%m-%dT%H:%M:%S.%f%z", "%Y-%m-%dT%H:%M:%S%z"):
        try:
            return datetime.strptime(date_str.strip(), fmt)
        except ValueError:
            continue
    return None


def _format_invoice_date(dt):
    """Format date as 'February 9, 2026'."""
    # %-d is macOS/Linux for no-leading-zero day
    try:
        return dt.strftime("%B %-d, %Y")
    except ValueError:
        # Windows fallback
        return dt.strftime("%B %d, %Y").replace(" 0", " ")


def _format_service_dates(created_dt, today_dt):
    """Format as 'Jan 15, 2025 - Feb 26, 2026' (abbreviated month, day, 4-digit year)."""
    month_abbr = {
        1: "Jan", 2: "Feb", 3: "Mar", 4: "Apr",
        5: "May", 6: "Jun", 7: "Jul", 8: "Aug",
        9: "Sep", 10: "Oct", 11: "Nov", 12: "Dec",
    }
    def _fmt(dt):
        try:
            return f"{month_abbr[dt.month]} {dt.strftime('%-d')}, {dt.year}"
        except ValueError:
            return f"{month_abbr[dt.month]} {dt.strftime('%d').lstrip('0')}, {dt.year}"
    return f"{_fmt(created_dt)} - {_fmt(today_dt)}"


def generate_invoice(row, output_dir="."):
    """Generate a single PDF invoice from a CSV row dict."""

    issue_key = row.get("issue_key", "").strip()
    pi_name = row.get("pi_name", "").strip()
    # Remove "Dr." or "Dr " prefix — invoice uses name only
    pi_name = re.sub(r"^Dr\.?\s*", "", pi_name)
    summary = row.get("summary", "").strip()
    quote_raw = row.get("quote", "").strip()
    created_raw = row.get("created", "").strip()

    # Validate required fields
    if not issue_key:
        print(f"  WARNING: Skipping row — missing issue_key")
        return False
    if not quote_raw:
        print(f"  WARNING: Skipping {issue_key} — missing quote")
        return False
    try:
        hours = float(quote_raw)
    except ValueError:
        print(f"  WARNING: Skipping {issue_key} — invalid quote value: {quote_raw!r}")
        return False
    if not pi_name:
        print(f"  WARNING: Skipping {issue_key} — missing pi_name")
        return False

    amount = hours * HOURLY_RATE
    today = datetime.now()

    # Date formatting
    invoice_date = _format_invoice_date(today)

    created_dt = _parse_created_date(created_raw) if created_raw else None
    if created_dt is None:
        created_dt = today
    dates_of_service = _format_service_dates(created_dt, today)

    ticket_num = _extract_ticket_number(issue_key)
    work_item = f"Ticket #{ticket_num}"

    output_path = os.path.join(output_dir, f"CONSOLIDATED INVOICE_{issue_key}.pdf")

    # --- Build the PDF ---
    doc = SimpleDocTemplate(
        output_path,
        pagesize=letter,
        topMargin=1.0 * inch,
        bottomMargin=1.0 * inch,
        leftMargin=1.0 * inch,
        rightMargin=1.0 * inch,
    )

    elements = []
    page_width = letter[0] - 2.0 * inch  # usable width = 6.5 inches

    # ---------------------------------------------------------------
    # Paragraph styles  (Calibri 10pt = body, 19pt = title)
    # ---------------------------------------------------------------
    s_title = ParagraphStyle(
        "Title", fontName=FONT_BOLD, fontSize=19,
        textColor=HexColor("#4270C1"), leading=23, alignment=TA_CENTER,
    )
    s_org = ParagraphStyle(
        "Org", fontName=FONT_BOLD, fontSize=10, leading=14, alignment=TA_LEFT,
    )
    s_field_left = ParagraphStyle(
        "FieldLeft", fontName=FONT, fontSize=10, leading=14, alignment=TA_LEFT,
    )
    s_field_right = ParagraphStyle(
        "FieldRight", fontName=FONT, fontSize=10, leading=14, alignment=TA_RIGHT,
    )
    s_header_cell = ParagraphStyle(
        "HeaderCell", fontName=FONT_BOLD, fontSize=10, leading=14,
        alignment=TA_CENTER,
    )
    s_data_cell = ParagraphStyle(
        "DataCell", fontName=FONT, fontSize=10, leading=14, alignment=TA_CENTER,
    )
    s_data_cell_left = ParagraphStyle(
        "DataCellLeft", fontName=FONT, fontSize=10, leading=14, alignment=TA_LEFT,
    )
    s_total = ParagraphStyle(
        "Total", fontName=FONT_BOLD_ITALIC, fontSize=10, leading=14,
        alignment=TA_LEFT,
    )
    s_footer = ParagraphStyle(
        "Footer", fontName=FONT_ITALIC, fontSize=10, leading=14, alignment=TA_LEFT,
    )

    # ---------------------------------------------------------------
    # Header section
    # ---------------------------------------------------------------
    logo = _logo_image()

    # Logo (left-aligned by default)
    elements.append(logo)
    # One line below logo: centered title
    elements.append(Spacer(1, 12))
    elements.append(Paragraph("CONSOLIDATED INVOICE", s_title))
    # Two lines below title: "Epic Research Reporting" left bold
    elements.append(Spacer(1, 24))
    elements.append(Paragraph("Epic Research Reporting", s_org))
    # One line below: right-aligned fields (labels bold, values not)
    elements.append(Spacer(1, 12))
    elements.append(
        Paragraph(f"<b>Dates of Service:</b> {dates_of_service}", s_field_right)
    )
    elements.append(
        Paragraph(f"<b>Invoice Date:</b> {invoice_date}", s_field_right)
    )
    elements.append(
        Paragraph(f"<b>Project Name:</b> {issue_key}", s_field_right)
    )
    # Next line: Bill to (bold, left)
    elements.append(Spacer(1, 12))
    elements.append(Paragraph("<b>Bill to</b>", s_field_left))
    # Next line: PI: (bold label, left)
    elements.append(Paragraph(f"<b>PI:</b> {pi_name}", s_field_left))
    # Department + Fund Number (bold labels, n/a not bold)
    elements.append(
        Paragraph(
            "<b>Department:</b>&nbsp;&nbsp;&nbsp;&nbsp;<b>Fund Number:</b> n/a",
            s_field_left,
        )
    )
    # Hourly Rate (bold label, value not bold)
    elements.append(
        Paragraph(f"<b>Hourly Rate:</b> ${HOURLY_RATE}", s_field_left)
    )
    elements.append(Spacer(1, 8))

    # ---------------------------------------------------------------
    # Data table  (matches template Rows 1-14)
    # ---------------------------------------------------------------
    col_widths = [
        page_width * 0.15,   # Work Item
        page_width * 0.52,   # Deliverables (wider for long text)
        page_width * 0.10,   # Hours
        page_width * 0.23,   # Amount
    ]

    def _build_table(n_empty):
        """Build the full table with n_empty blank rows and return it."""
        td = []
        td.append([
            Paragraph("Work Item", s_header_cell),
            Paragraph("Deliverables", s_header_cell),
            Paragraph("Hours", s_header_cell),
            Paragraph("Amount", s_header_cell),
        ])
        td.append([
            Paragraph(work_item, s_data_cell),
            Paragraph(summary, s_data_cell_left),
            Paragraph(str(hours), s_data_cell),
            Paragraph(f"${amount:,.2f}", s_data_cell),
        ])
        for _ in range(n_empty):
            td.append(["", "", "", ""])
        td.append([
            Paragraph(f"<b><i>Total:&nbsp;&nbsp;${amount:,.2f}</i></b>", s_total),
            "", "", "",
        ])
        td.append([
            Paragraph(
                "<i>Thank you for allowing us to support your research. "
                "Please note all future changes to the database will be billed "
                f"at the ${HOURLY_RATE} an hour charge back rate. The rate has "
                "been approved in 2025 by Finance and Compliance.</i>",
                s_footer,
            ), "", "", "",
        ])
        nr = len(td)
        t_row = nr - 2
        f_row = nr - 1
        tbl = Table(td, colWidths=col_widths)
        tbl.setStyle(TableStyle([
            ("FONTNAME", (0, 0), (-1, -1), FONT),
            ("FONTSIZE", (0, 0), (-1, -1), 10),
            ("VALIGN",   (0, 0), (-1, -1), "MIDDLE"),
            ("TOPPADDING",    (0, 0), (-1, -1), 4),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 4),
            ("LEFTPADDING",   (0, 0), (-1, -1), 4),
            ("RIGHTPADDING",  (0, 0), (-1, -1), 4),
            ("GRID", (0, 0), (-1, t_row - 1), 0.75, black),
            ("BACKGROUND", (0, 0), (-1, 0), white),
            ("FONTNAME",   (0, 0), (-1, 0), FONT_BOLD),
            ("ALIGN",      (0, 0), (-1, 0), "CENTER"),
            ("ALIGN", (0, 1), (0, t_row - 1), "CENTER"),
            ("ALIGN", (2, 1), (2, t_row - 1), "CENTER"),
            ("ALIGN", (3, 1), (3, t_row - 1), "CENTER"),
            ("SPAN", (0, t_row), (-1, t_row)),
            ("BOX",  (0, t_row), (-1, t_row), 0.75, black),
            ("TOPPADDING",    (0, t_row), (-1, t_row), 6),
            ("BOTTOMPADDING", (0, t_row), (-1, t_row), 6),
            ("SPAN", (0, f_row), (-1, f_row)),
            ("TOPPADDING",    (0, f_row), (-1, f_row), 8),
            ("BOTTOMPADDING", (0, f_row), (-1, f_row), 8),
        ]))
        return tbl

    def _page_count(elems):
        """Build PDF to memory and return number of pages."""
        buf = BytesIO()
        test_doc = SimpleDocTemplate(
            buf, pagesize=letter,
            topMargin=1.0 * inch, bottomMargin=1.0 * inch,
            leftMargin=1.0 * inch, rightMargin=1.0 * inch,
        )
        test_doc.build(copy.deepcopy(elems))
        # Count pages by scanning the PDF bytes for /Type /Page
        pdf_bytes = buf.getvalue()
        # Use a simple count of page markers
        import re as _re
        pages = len(_re.findall(rb"/Type\s*/Page(?!s)", pdf_bytes))
        return pages

    # Try decreasing empty rows until everything fits on one page
    for num_empty in range(10, -1, -1):
        main_table = _build_table(num_empty)
        trial = elements + [main_table]
        if _page_count(trial) == 1:
            break

    elements.append(main_table)

    doc.build(elements)
    print(f"  Generated: {output_path}")
    return True


def _ordinal_date(dt):
    """Format date as 'February 9th, 2026' with ordinal suffix."""
    day = dt.day
    if 11 <= day <= 13:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(day % 10, "th")
    try:
        month_day = dt.strftime(f"%B %-d")
    except ValueError:
        month_day = dt.strftime(f"%B %d").replace(" 0", " ")
    return f"{month_day}{suffix}, {dt.year}"


